namespace sv_32cb8b93b0794bd0bc1603995165a8dc;

public enum ScreenSize
{
    Mobile,
    Tablet,
    Desktop
}

export function registerResizeHandler(dotNetRef) {
    const categorize = () => {
        const w = window.innerWidth;
        if (w < 768) return 0;       // Mobile
        if (w < 1024) return 1;      // Tablet
        return 2;                     // Desktop
    };

    let current = categorize();
    dotNetRef.invokeMethodAsync('OnBrowserResize', current);

    const handler = () => {
        const next = categorize();
        if (next !== current) {
            current = next;
            dotNetRef.invokeMethodAsync('OnBrowserResize', current);
        }
    };

    window.addEventListener('resize', handler);
    return handler;
}

export function unregisterResizeHandler(handler) {
    window.removeEventListener('resize', handler);
}

