            _handler = await _module.InvokeAsync<IJSObjectReference>(
                "registerResizeHandler", _dotNetRef);
        }
    }

    [JSInvokable]
    public void OnBrowserResize(int category)
    {
        var newSize = (ScreenSize)category;
